from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql
import logging

app = Flask(__name__)

# Database configuration
DB_CONFIG = {
    'host': 'localhost',
    'database': 'analytics_db',
    'user': 'analytics_user',
    'password': 'analytics_password',
    'port': 5432
}

def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)

def validate_table_name(table_name):
    # Allow only alphanumeric characters and underscores
    if not table_name.replace('_', '').isalnum():
        raise ValueError("Invalid table name")
    return table_name

def validate_column_name(column_name):
    # Allow only alphanumeric characters and underscores
    if not column_name.replace('_', '').isalnum():
        raise ValueError("Invalid column name")
    return column_name

def build_select_query(table_name, columns=None, filters=None):
    table_name = validate_table_name(table_name)
    
    # Build column list
    if columns:
        validated_columns = [validate_column_name(col) for col in columns]
        column_list = ', '.join(validated_columns)
    else:
        column_list = '*'
    
    # Build query
    query = sql.SQL("SELECT {} FROM {}").format(
        sql.SQL(column_list),
        sql.Identifier(table_name)
    )
    
    # Add filters if provided
    if filters:
        where_conditions = []
        params = []
        
        for key, value in filters.items():
            validated_column = validate_column_name(key)
            where_conditions.append(sql.SQL("{} = %s").format(sql.Identifier(validated_column)))
            params.append(value)
        
        if where_conditions:
            query += sql.SQL(" WHERE ") + sql.SQL(" AND ").join(where_conditions)
            return query, params
    
    return query, []

@app.route('/query', methods=['POST'])
def execute_query():
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'No data provided'}), 400
        
        table_name = data.get('table')
        columns = data.get('columns')
        filters = data.get('filters')
        
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400
        
        # Build query
        query, params = build_select_query(table_name, columns, filters)
        
        # Execute query
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute(query, params)
        
        # Get column names
        column_names = [desc[0] for desc in cursor.description]
        
        # Fetch results
        rows = cursor.fetchall()
        results = [dict(zip(column_names, row)) for row in rows]
        
        cursor.close()
        conn.close()
        
        return jsonify({
            'success': True,
            'data': results,
            'count': len(results)
        })
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        logging.error(f"Database error: {e}")
        return jsonify({'error': 'Database error occurred'}), 500
    except Exception as e:
        logging.error(f"Unexpected error: {e}")
        return jsonify({'error': 'An unexpected error occurred'}), 500

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)